This script uses Python's built-in `random` module to generate an array of `n` integers between a specified minimum (`min`) and maximum (`max`).

```python
import random

def generate_random_array(count, min_val=0, max_val=100):
    """
    Generates an array/list of random integers.

    Args:
        count (int): Number of elements to generate.
        min_val (int): Minimum inclusive value (default: 0).
        max_val (int): Maximum exclusive value. Note: 
                      The range is [min_val, max_val).

    Returns:
        list[int]: A list containing random numbers.
    """
    return [random.randint(min_val, max_val - 1) for _ in range(count)]

# Configuration
array_size = 10
lower_limit = 1
upper_limit = 50

# Generate and print
result = generate_random_array(array_size, lower_limit, upper_limit + 1)
print(f"Generated {array_size} random numbers between {lower_limit} and {upper_limit}:")
print(result)
```

