This script generates an array where each number is a floating-point decimal between 0 and 1, which is usually what browsers provide by default. If you need integers, see the logic inside comments.

```javascript
/**
 * Generates an array of random numbers.
 * By default in JS, Math.random() returns a float between 0 (inclusive) and 1 (exclusive).
 */

function generateRandomArray(size, multiplier = 1) {
  const result = [];

  for (let i = 0; i < size; i++) {
    // Generates a number between 0 and 'multiplier'
    result.push(Math.random() * multiplier);
  }

  return result;
}

// Usage Example
const numberOfElements = 7;
const maxValue = 100; 

const randomNumbers = generateRandomArray(numberOfElements, maxValue);

console.log(`Generated ${randomNumbers.length} random numbers:`);
