## Example Implementation in C++

```cpp
struct Node {
    int key;
    Node *left = nullptr;
    Node *right = nullptr;
};

Node* insert(Node* root, int key) {
    if (root == nullptr) {
        return new Node{key, nullptr, nullptr};
    }

    Node* curr = root;
    Node* parent = nullptr;

    while (curr != nullptr) {
        parent = curr;
        if (key < curr->key) {
            curr = curr->left;
        } else if (key > curr->key) {
            curr = curr->right;
        } else {
            // duplicate -> nothing
            return root;
        }
    }

    Node* newNode = new Node{key, nullptr, nullptr};
    if (parent && key < parent->key) {
        parent->left = newNode;
    } else if (parent && key > parent->key) {
        parent->right = newNode;
    }

    return root;
}

bool searchBST(Node* root, int key) {
    while (root != nullptr) {
        if (key == root->key) {
            return true;
        } else if (key < root->key) {
            root = root->left;
        } else {
            root = root->right;
        }
    }
    return false;
}

int minValue(Node* root) {
    while (root->left != nullptr) {
        root = root->left;
    }
    return root->key;
}

Node* deleteBST(Node* root, int key) {
    if (root == nullptr) {
        return nullptr;
    }

    if (key < root->key) {
        root->left = deleteBST(root->left, key);
    } else if (key > root->key) {
        root->right = deleteBST(root->right, key);
    } else {
        if (root->left == nullptr) {
            Node* temp = root->right;
            delete root;
            return temp;
        } else if (root->right == nullptr) {
            Node* temp = root->left;
            delete root;
            return temp;
        }

        // Two children
        Node* succParent = root;
        Node* succ = root->right;

        // Find inorder successor's parent
        while (succ->left != nullptr) {
            succParent = succ;
            succ = succ->left;
        }

        // Copy successor's data
        root->key = succ->key;

        // Delete duplicate node (successor)
        if (succParent->left == succ) {
            succParent->left = succ->right;
        } else {
            succParent->right = succ->right;
        }

        delete succ;
    }
    return root;
}
```

